class Solution {
    public int maximumLengthSubstring(String s) {
        int count[] = new int[26];
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            int c = s.charAt(i) - 'a';
            count[c]++;
            if (count[c] > 2) {
                count[c]--;
            }
            maxLength = Math.max(maxLength, i - count[s.charAt(i - 1) - 'a' + 1);
        }
        return maxLength;
    }
}
```

